{
  "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
  "contentVersion": "1.0.0.0",
  "parameters": {
    "edgeZoneName": {
      "type": "string",
      "defaultValue": "microsofteagle",
      "metadata": { "description": "Name of the Azure Edge Zone extended location" }
    },
    "location": {
      "type": "string",
      "defaultValue": "eastus"
    }
  },
  "resources": [
    {
      "type": "Microsoft.Network/virtualNetworks",
      "apiVersion": "2023-04-01",
      "name": "myEdgeVNet",
      "location": "[parameters('location')]",
      "extendedLocation": {
        "type": "EdgeZone",
        "name": "[parameters('edgeZoneName')]"
      },
      "properties": {
        "addressSpace": { "addressPrefixes": ["10.1.0.0/16"] },
        "subnets": [{ "name": "default", "properties": { "addressPrefix": "10.1.0.0/24" } }]
      }
    },
    {
      "type": "Microsoft.Compute/virtualMachines",
      "apiVersion": "2023-03-01",
      "name": "myEdgeVM",
      "location": "[parameters('location')]",
      "extendedLocation": {
        "type": "EdgeZone",
        "name": "[parameters('edgeZoneName')]"
      },
      "properties": {
        "hardwareProfile": { "vmSize": "Standard_D4s_v3" },
        "storageProfile": {
          "imageReference": {
            "publisher": "Canonical",
            "offer": "0001-com-ubuntu-server-jammy",
            "sku": "22_04-lts-gen2",
            "version": "latest"
          },
          "osDisk": { "createOption": "FromImage", "managedDisk": { "storageAccountType": "Premium_LRS" } }
        },
        "networkProfile": {
          "networkInterfaces": [{ "id": "[resourceId('Microsoft.Network/networkInterfaces', 'myEdgeNIC')]" }]
        }
      }
    }
  ]
}
